import React, { useState, useEffect } from 'react';
import { db } from '../../../src/utils/db';

export default function Dashboard() {
  const [stats, setStats] = useState({
    revenue: 0,
    ordersCount: 0,
    lowStockCount: 0,
    activeDebts: 0
  });

  useEffect(() => {
    try {
      db.init();
      const products = db.getProducts();
      const debts = db.getDebts();

      // Calculate today's revenue from local attendance or today's orders
      const logs = db.getAttendance();
      let todayRev = 0;
      logs.forEach(l => {
        todayRev += db.getShiftSales(l.userId);
      });

      // Low stock count
      const lowStock = products.filter(p => p.stock <= (p.minStock || 5)).length;

      // Active debts
      const activeDebtsVal = debts.filter(d => d.balance > 0).reduce((sum, d) => sum + d.balance, 0);

      setStats({
        revenue: todayRev,
        ordersCount: db.getOrders ? db.getOrders().length : 0,
        lowStockCount: lowStock,
        activeDebts: activeDebtsVal
      });
    } catch (e) {
      console.error(e);
    }
  }, []);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* Page Title */}
      <div>
        <h2 style={{ fontSize: '20px', color: 'var(--text-gold)', fontWeight: 'bold' }}>📊 ພາບລວມລະບົບ / Executive Dashboard</h2>
        <p style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>Real-time business insights from your local database</p>
      </div>

      {/* KPI Cards Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '16px' }}>

        <div className="glass-panel-v2" style={{ borderLeft: '4px solid var(--gold-primary)' }}>
          <p style={{ fontSize: '0.72rem', textTransform: 'uppercase', color: 'var(--text-muted)' }}>ລາຍຮັບມື້ນີ້ / Today Revenue</p>
          <h3 style={{ fontSize: '24px', fontWeight: 'bold', margin: '8px 0', color: 'var(--text-primary)' }}>
            {stats.revenue.toLocaleString()} ₭
          </h3>
          <p style={{ fontSize: '0.68rem', color: '#22c55e' }}>✓ active shift calculations</p>
        </div>

        <div className="glass-panel-v2" style={{ borderLeft: '4px solid #3498db' }}>
          <p style={{ fontSize: '0.72rem', textTransform: 'uppercase', color: 'var(--text-muted)' }}>ຈຳນວນອໍເດີ້ / Total Orders</p>
          <h3 style={{ fontSize: '24px', fontWeight: 'bold', margin: '8px 0', color: 'var(--text-primary)' }}>
            {stats.ordersCount}
          </h3>
          <p style={{ fontSize: '0.68rem', color: 'var(--text-secondary)' }}>orders inside local DB</p>
        </div>

        <div className="glass-panel-v2" style={{ borderLeft: '4px solid #e74c3c' }}>
          <p style={{ fontSize: '0.72rem', textTransform: 'uppercase', color: 'var(--text-muted)' }}>ສິນຄ້າໃກ້ໝົດ / Low Stock Warnings</p>
          <h3 style={{ fontSize: '24px', fontWeight: 'bold', margin: '8px 0', color: '#e74c3c' }}>
            {stats.lowStockCount}
          </h3>
          <p style={{ fontSize: '0.68rem', color: '#e74c3c' }}>requires restocking soon</p>
        </div>

        <div className="glass-panel-v2" style={{ borderLeft: '4px solid #f39c12' }}>
          <p style={{ fontSize: '0.72rem', textTransform: 'uppercase', color: 'var(--text-muted)' }}>ຍອດຄ້າງຊຳລະ / Outstanding Debts</p>
          <h3 style={{ fontSize: '24px', fontWeight: 'bold', margin: '8px 0', color: '#f39c12' }}>
            {stats.activeDebts.toLocaleString()} ₭
          </h3>
          <p style={{ fontSize: '0.68rem', color: 'var(--text-secondary)' }}>linked to customer accounts</p>
        </div>

      </div>

      {/* Main Charts & Activity Panel */}
      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>

        {/* Sales Performance Visualizer */}
        <div className="glass-panel-v2" style={{ minHeight: '300px', display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <h3 style={{ fontSize: '0.9rem', color: 'var(--text-gold)', fontWeight: 'bold' }}>📈 ແນວໂນ້ມການຂາຍ / Sales Performance Chart</h3>

          <div style={{ flex: 1, display: 'flex', alignItems: 'flex-end', justifyContent: 'space-around', padding: '20px 0', borderBottom: '1px solid var(--border-color)' }}>
            {/* SVG sales visualizer bars */}
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '40px', height: '140px', background: 'linear-gradient(to top, var(--gold-dark), var(--gold-primary))', borderRadius: '4px 4px 0 0', boxShadow: '0 0 10px rgba(212,175,55,0.2)' }}/>
              <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>Mon</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '40px', height: '90px', background: 'linear-gradient(to top, var(--gold-dark), var(--gold-primary))', borderRadius: '4px 4px 0 0' }}/>
              <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>Tue</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '40px', height: '180px', background: 'linear-gradient(to top, var(--gold-dark), var(--gold-primary))', borderRadius: '4px 4px 0 0', boxShadow: '0 0 15px rgba(212,175,55,0.3)' }}/>
              <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>Wed</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '40px', height: '120px', background: 'linear-gradient(to top, var(--gold-dark), var(--gold-primary))', borderRadius: '4px 4px 0 0' }}/>
              <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>Thu</span>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '40px', height: '220px', background: 'linear-gradient(to top, var(--gold-dark), var(--gold-primary))', borderRadius: '4px 4px 0 0', boxShadow: '0 0 20px rgba(212,175,55,0.4)' }}/>
              <span style={{ fontSize: '0.7rem', color: 'var(--text-gold)', fontWeight: 'bold' }}>Today</span>
            </div>
          </div>
        </div>

        {/* System Logs / Alerts Widget */}
        <div className="glass-panel-v2" style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
          <h3 style={{ fontSize: '0.9rem', color: 'var(--text-gold)', fontWeight: 'bold' }}>🔔 ແຈ້ງເຕືອນລະບົບ / Alerts</h3>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', overflowY: 'auto', maxHeight: '240px' }}>
            {stats.lowStockCount > 0 && (
              <div style={{ padding: '10px', borderRadius: 'var(--radius-sm)', background: 'rgba(231,76,60,0.1)', border: '1px solid rgba(231,76,60,0.2)', fontSize: '0.75rem', color: '#e74c3c' }}>
                ⚠️ Low Stock Alert: {stats.lowStockCount} items have reached minimum safety stock levels.
              </div>
            )}

            <div style={{ padding: '10px', borderRadius: 'var(--radius-sm)', background: 'rgba(52,152,219,0.1)', border: '1px solid rgba(52,152,219,0.2)', fontSize: '0.75rem', color: '#3498db' }}>
              ℹ️ Local Sync Done: All products and customer logs synchronized with db_shared.json successfully.
            </div>

            <div style={{ padding: '10px', borderRadius: 'var(--radius-sm)', background: 'rgba(46,204,113,0.1)', border: '1px solid rgba(46,204,113,0.2)', fontSize: '0.75rem', color: '#2ec471' }}>
              ✓ Shift Status: Employee shift active. Logging payroll and sales margins in real-time.
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}
